namespace Payments;

public interface IPaymentProvider
{
    Task<ProviderResponse> CreateChargeAsync(string cardToken, decimal amount);
    Task<ProviderResponse> CreateRefundAsync(string chargeId);
}

public record ProviderResponse(string Id, bool Succeeded);
public record ChargeResult(string ChargeId, bool Success);
public record RefundResult(string RefundId, bool Success);
public record WebhookResult(string EventType, bool Handled);

public sealed class PaymentGateway
{
    private readonly IPaymentProvider _provider;

    public PaymentGateway(IPaymentProvider provider)
    {
        _provider = provider ?? throw new ArgumentNullException(nameof(provider));
    }

    public async Task<ChargeResult> ChargeAsync(string cardToken, decimal amount)
    {
        if (string.IsNullOrWhiteSpace(cardToken))
            throw new ArgumentException("Card token is required.", nameof(cardToken));
        if (amount <= 0)
            throw new ArgumentException("Amount must be positive.", nameof(amount));
        if (amount > 999_999.99m)
            throw new ArgumentException("Amount exceeds maximum.", nameof(amount));

        try
        {
            var response = await _provider.CreateChargeAsync(cardToken, amount);
            return new ChargeResult(response.Id, response.Succeeded);
        }
        catch (Exception ex) when (ex is not ArgumentException)
        {
            return new ChargeResult(string.Empty, false);
        }
    }

    public async Task<RefundResult> RefundAsync(string chargeId)
    {
        if (string.IsNullOrWhiteSpace(chargeId))
            throw new ArgumentException("Charge ID is required.", nameof(chargeId));

        try
        {
            var response = await _provider.CreateRefundAsync(chargeId);
            return new RefundResult(response.Id, response.Succeeded);
        }
        catch (Exception ex) when (ex is not ArgumentException)
        {
            return new RefundResult(string.Empty, false);
        }
    }

    public WebhookResult ProcessWebhook(string eventType, string payload)
    {
        if (string.IsNullOrWhiteSpace(eventType))
            throw new ArgumentException("Event type is required.", nameof(eventType));
        if (string.IsNullOrWhiteSpace(payload))
            throw new ArgumentException("Payload is required.", nameof(payload));

        return eventType switch
        {
            "charge.succeeded" or "charge.failed" or
            "refund.succeeded" or "refund.failed" => new WebhookResult(eventType, Handled: true),
            _ => new WebhookResult(eventType, Handled: false),
        };
    }
}

