using Moq;
using Payments;

namespace Payments.Tests;

[TestClass]
public class PaymentGatewayConstructorTests
{
    [TestMethod]
    public void Constructor_NullProvider_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => new PaymentGateway(null!));
    }

    [TestMethod]
    public void Constructor_ValidProvider_DoesNotThrow()
    {
        var provider = new Mock<IPaymentProvider>().Object;
        var gateway = new PaymentGateway(provider);
        Assert.IsNotNull(gateway);
    }
}

[TestClass]
public class ChargeAsyncTests
{
    private Mock<IPaymentProvider> _mockProvider = null!;
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _mockProvider = new Mock<IPaymentProvider>();
        _gateway = new PaymentGateway(_mockProvider.Object);
    }

    // --- Validation tests ---

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_InvalidCardToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token!, 10m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-0.01)]
    public async Task ChargeAsync_NonPositiveAmount_ThrowsArgumentException(double amount)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid", (decimal)amount));
    }

    [TestMethod]
    public async Task ChargeAsync_AmountExceedsMaximum_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid", 1_000_000m));
    }

    [TestMethod]
    public async Task ChargeAsync_AmountAtMaximum_DoesNotThrow()
    {
        _mockProvider
            .Setup(p => p.CreateChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
            .ReturnsAsync(new ProviderResponse("ch_1", true));

        var result = await _gateway.ChargeAsync("tok_valid", 999_999.99m);
        Assert.IsTrue(result.Success);
    }

    // --- Happy path tests ---

    [TestMethod]
    public async Task ChargeAsync_SuccessfulCharge_ReturnsChargeIdAndSuccess()
    {
        _mockProvider
            .Setup(p => p.CreateChargeAsync("tok_abc", 49.99m))
            .ReturnsAsync(new ProviderResponse("ch_123", true));

        var result = await _gateway.ChargeAsync("tok_abc", 49.99m);

        Assert.AreEqual("ch_123", result.ChargeId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCharge_ReturnsSuccessFalse()
    {
        _mockProvider
            .Setup(p => p.CreateChargeAsync("tok_declined", 100m))
            .ReturnsAsync(new ProviderResponse("ch_456", false));

        var result = await _gateway.ChargeAsync("tok_declined", 100m);

        Assert.AreEqual("ch_456", result.ChargeId);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_SmallAmount_Succeeds()
    {
        _mockProvider
            .Setup(p => p.CreateChargeAsync(It.IsAny<string>(), 0.01m))
            .ReturnsAsync(new ProviderResponse("ch_penny", true));

        var result = await _gateway.ChargeAsync("tok_valid", 0.01m);
        Assert.IsTrue(result.Success);
        Assert.AreEqual("ch_penny", result.ChargeId);
    }

    // --- Provider forwards correct arguments ---

    [TestMethod]
    public async Task ChargeAsync_ForwardsTokenAndAmountToProvider()
    {
        _mockProvider
            .Setup(p => p.CreateChargeAsync("tok_xyz", 25.50m))
            .ReturnsAsync(new ProviderResponse("ch_1", true))
            .Verifiable();

        await _gateway.ChargeAsync("tok_xyz", 25.50m);

        _mockProvider.Verify(p => p.CreateChargeAsync("tok_xyz", 25.50m), Times.Once);
    }

    // --- Error handling ---

    [TestMethod]
    public async Task ChargeAsync_ProviderThrows_ReturnsEmptyIdAndFailure()
    {
        _mockProvider
            .Setup(p => p.CreateChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
            .ThrowsAsync(new InvalidOperationException("Network error"));

        var result = await _gateway.ChargeAsync("tok_valid", 10m);

        Assert.AreEqual(string.Empty, result.ChargeId);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderThrowsTimeout_ReturnsFailure()
    {
        _mockProvider
            .Setup(p => p.CreateChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
            .ThrowsAsync(new TimeoutException());

        var result = await _gateway.ChargeAsync("tok_valid", 10m);
        Assert.IsFalse(result.Success);
    }
}

[TestClass]
public class RefundAsyncTests
{
    private Mock<IPaymentProvider> _mockProvider = null!;
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _mockProvider = new Mock<IPaymentProvider>();
        _gateway = new PaymentGateway(_mockProvider.Object);
    }

    // --- Validation tests ---

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_InvalidChargeId_ThrowsArgumentException(string? chargeId)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(chargeId!));
    }

    // --- Happy path tests ---

    [TestMethod]
    public async Task RefundAsync_SuccessfulRefund_ReturnsRefundIdAndSuccess()
    {
        _mockProvider
